//! Channel close circuit (building block B, phase 2): merchant-pull subscription channel.
//!
//! `verify_channel_close` settles a one-way shielded payment channel. It opens the hidden `cap`
//! commitment and the subscriber-signed cumulative commitment `C_k = Commit(drawn, r_k)`, verifies
//! the subscriber's authorization signature IN-CIRCUIT (Schnorr over the embedded Grumpkin curve),
//! asserts `drawn <= cap`, and mints two shielded notes: `drawn` to the merchant and `cap - drawn`
//! back to the subscriber. The contract sees only opaque Poseidon handles + the verifier result, so
//! it does no curve math and no signature verification. See `claude-docs/channel_interface.md`.
//!
//! Schnorr over Grumpkin: the embedded curve's coordinates are BN254 `Fr` (Noir's `Field`) but its
//! SCALARS live in BN254 `Fq` (the larger base field). The challenge `e = Poseidon2(...)` is an `Fr`
//! element (< Fr < Fq), safe to lift via `EmbeddedCurveScalar::from_field`. The response `s` is
//! computed off-circuit in `Fq` and can land in `[Fr, Fq)`, so it is passed as the two limbs
//! `(s_lo, s_hi)` of an `EmbeddedCurveScalar` -- NEVER as a `Field` (which would reduce it mod Fr).
use crate::escrow::{bind, commit, point_hash, DOMAIN_ESCROW_REFUND};
use crate::{derive_owner_pk, Note};
use poseidon::poseidon2::Poseidon2;
use std::embedded_curve_ops::{multi_scalar_mul, EmbeddedCurvePoint, EmbeddedCurveScalar};

/// Domain tag for the merchant draw binding (ASCII "ozky_mrc"). Distinct from the escrow refund
/// domain reused for the subscriber binding, so neither output can be redirected to the other.
pub global DOMAIN_CHANNEL_MERCHANT: Field = 0x6f7a6b795f6d7263;

/// The Schnorr base point: `G0 = Commit(1, 0)`, the Pedersen value generator (already parity-pinned
/// in `claude-docs/escrow_parity.md` / the client's `pedersen` module). Grumpkin has prime order, so
/// any non-identity point generates the group; reusing G0 means the client needs no new generator.
pub global SCHNORR_G: EmbeddedCurvePoint = EmbeddedCurvePoint {
    x: 0x083e7911d835097629f0067531fc15cafd79a89beecb39903f69572c636f4a5a,
    y: 0x1a7f5efaad7f315c25a918f30cc8d7333fccab7ad7c90f14de81bcc528f9935d,
    is_infinite: false,
};

/// Verify a Schnorr signature `(R, s)` over `msg` under public key `pk = sk * G0`.
/// `e = Poseidon2([R.x, R.y, pk.x, pk.y, msg])`; the check is `s * G0 == R + e * pk`. `s` arrives as
/// limbs `(s_lo, s_hi)` (an `Fq` scalar that may exceed `Fr`); `e` is an `Fr` element lifted directly.
pub fn verify_schnorr(
    pk: EmbeddedCurvePoint,
    sig_r: EmbeddedCurvePoint,
    s_lo: Field,
    s_hi: Field,
    msg: Field,
) {
    let e = Poseidon2::hash([sig_r.x, sig_r.y, pk.x, pk.y, msg], 5);
    let s = EmbeddedCurveScalar::new(s_lo, s_hi);
    let e_scalar = EmbeddedCurveScalar::from_field(e);
    let lhs = multi_scalar_mul([SCHNORR_G], [s]);
    let e_pk = multi_scalar_mul([pk], [e_scalar]);
    let rhs = sig_r + e_pk;
    assert(lhs.x == rhs.x);
    assert(lhs.y == rhs.y);
}

pub struct CloseWitness {
    // public
    pub domain_sep: Field,
    pub asset_tag: Field,
    pub epoch: Field,
    pub cap_hash: Field,
    pub auth_key: Field,
    pub valid_after_ledger: Field,
    pub merchant_out: Field,
    pub subscriber_out: Field,
    pub merchant_bind: Field,
    pub subscriber_bind: Field,
    // private
    pub cap: Field,
    pub r_cap: Field,
    pub drawn: Field,
    pub r_k: Field,
    pub channel_id: Field,
    pub pk: EmbeddedCurvePoint,
    pub sig_r: EmbeddedCurvePoint,
    pub s_lo: Field,
    pub s_hi: Field,
    pub merchant_pk: Field,
    pub m_salt: Field,
    pub merchant_blinding: Field,
    pub merchant_rho: Field,
    pub subscriber_pk: Field,
    pub s_salt: Field,
    pub subscriber_blinding: Field,
    pub subscriber_rho: Field,
}

#[allow(clippy::too_many_arguments)]
pub fn verify_channel_close(
    domain_sep: Field,
    asset_tag: Field,
    epoch: Field,
    cap_hash: Field,
    auth_key: Field,
    valid_after_ledger: Field,
    merchant_out: Field,
    subscriber_out: Field,
    merchant_bind: Field,
    subscriber_bind: Field,
    cap: Field,
    r_cap: Field,
    drawn: Field,
    r_k: Field,
    channel_id: Field,
    pk: EmbeddedCurvePoint,
    sig_r: EmbeddedCurvePoint,
    s_lo: Field,
    s_hi: Field,
    merchant_pk: Field,
    m_salt: Field,
    merchant_blinding: Field,
    merchant_rho: Field,
    subscriber_pk: Field,
    s_salt: Field,
    subscriber_blinding: Field,
    subscriber_rho: Field,
) {
    assert(domain_sep != 0);
    epoch.assert_max_bit_size::<32>();
    cap.assert_max_bit_size::<64>();
    drawn.assert_max_bit_size::<64>();
    // drawn <= cap (both range-bound, so integer order); remainder stays in [0, cap].
    assert(!cap.lt(drawn));
    let remainder = cap - drawn;

    // Open the cap: cap_hash pins the point, which must be Commit(cap, r_cap).
    let c_cap = commit(cap, r_cap);
    assert(point_hash(c_cap) == cap_hash);

    // The subscriber-signed cumulative commitment for this period.
    let c_k = commit(drawn, r_k);

    // The auth-key handle binds the per-channel signing public key.
    assert(point_hash(pk) == auth_key);
    // The subscriber authorized exactly (channel_id, valid_after_ledger, C_k).
    let msg = Poseidon2::hash([channel_id, valid_after_ledger, c_k.x, c_k.y], 4);
    verify_schnorr(pk, sig_r, s_lo, s_hi, msg);

    // Mint the draw to the merchant (only the merchant key + salt opens merchant_bind).
    let m_note = Note {
        value: drawn,
        asset_tag,
        owner_pk: merchant_pk,
        blinding: merchant_blinding,
        epoch,
        rho: merchant_rho,
    };
    assert(m_note.commitment() == merchant_out);
    assert(bind(DOMAIN_CHANNEL_MERCHANT, merchant_pk, m_salt) == merchant_bind);

    // Mint the remainder back to the subscriber (reuses the escrow refund binding set at open).
    let s_note = Note {
        value: remainder,
        asset_tag,
        owner_pk: subscriber_pk,
        blinding: subscriber_blinding,
        epoch,
        rho: subscriber_rho,
    };
    assert(s_note.commitment() == subscriber_out);
    assert(bind(DOMAIN_ESCROW_REFUND, subscriber_pk, s_salt) == subscriber_bind);
}

impl CloseWitness {
    pub fn run(self) {
        verify_channel_close(
            self.domain_sep,
            self.asset_tag,
            self.epoch,
            self.cap_hash,
            self.auth_key,
            self.valid_after_ledger,
            self.merchant_out,
            self.subscriber_out,
            self.merchant_bind,
            self.subscriber_bind,
            self.cap,
            self.r_cap,
            self.drawn,
            self.r_k,
            self.channel_id,
            self.pk,
            self.sig_r,
            self.s_lo,
            self.s_hi,
            self.merchant_pk,
            self.m_salt,
            self.merchant_blinding,
            self.merchant_rho,
            self.subscriber_pk,
            self.s_salt,
            self.subscriber_blinding,
            self.subscriber_rho,
        );
    }
}

// ----------------------------- demo witness + tests -----------------------------
//
// The positive vector below (signing key, nonce point R, and response s) is produced by the native
// Rust signer (`core/channel.rs::tests::print_schnorr_parity_vectors`) using the SAME Poseidon2 and
// the SAME Grumpkin base G0 as this circuit, because a valid Schnorr signature needs Fq scalar-field
// arithmetic the circuit cannot do on itself. The Noir test then proves the circuit ACCEPTS it, which
// is what pins client<->circuit signature parity (the Pedersen/Poseidon-style reference-vector dance).

/// A deterministic close: cap=1000, drawn=600, remainder=400, channel_id=1, valid_after=50. The
/// signing material is the parity vector; `pk = sk*G0`, `R = k*G0`, `s = (k + e*sk) mod Fq`.
pub fn close_demo() -> CloseWitness {
    let asset_tag = 1;
    let epoch = 5;
    let domain_sep = 0xabc;
    let cap = 1000;
    let r_cap = 0xca9;
    let drawn = 600;
    let r_k = 0xd4a;
    let channel_id = 1;
    let valid_after_ledger = 50;

    // --- signature parity vector (from core::pedersen::tests::print_schnorr_parity_vectors,
    //     signing key sk=0x1234567, nonce k=0x89abcdef; pk = sk*G0, R = k*G0, s = (k+e*sk) mod Fq) ---
    let pk = EmbeddedCurvePoint {
        x: 0x102f436ca51e10edbcc14790feebb4d5f4859b103b735d38c5391829fc67833e,
        y: 0x01ee2d6fb91923147be9d69c48c1487eb75562f0a02de04ca52d3f2ec1d302b0,
        is_infinite: false,
    };
    let sig_r = EmbeddedCurvePoint {
        x: 0x0cedf0ec95adaf1df3e425efc2382bf4cec5c2b663110a21e014c5869ebd6726,
        y: 0x2fc28988d4a06930b7aa9fe2825916b8e842a873aac34eb88fc425c72791307d,
        is_infinite: false,
    };
    let s_lo = 0xa7cfbb9e6051930fa3f7f5bd66c9d202;
    let s_hi = 0x1512fadc1e5a6772f33b6ab3c677c1cc;
    // --- end parity vector ---

    let merchant_sk = 0x3e;
    let merchant_pk = derive_owner_pk(merchant_sk);
    let m_salt = 0x3e17;
    let merchant_blinding = 222;
    let merchant_rho = 333;

    let subscriber_sk = 0x5b;
    let subscriber_pk = derive_owner_pk(subscriber_sk);
    let s_salt = 0x5b17;
    let subscriber_blinding = 444;
    let subscriber_rho = 555;

    let c_cap = commit(cap, r_cap);
    let m_note = Note {
        value: drawn,
        asset_tag,
        owner_pk: merchant_pk,
        blinding: merchant_blinding,
        epoch,
        rho: merchant_rho,
    };
    let s_note = Note {
        value: cap - drawn,
        asset_tag,
        owner_pk: subscriber_pk,
        blinding: subscriber_blinding,
        epoch,
        rho: subscriber_rho,
    };

    CloseWitness {
        domain_sep,
        asset_tag,
        epoch,
        cap_hash: point_hash(c_cap),
        auth_key: point_hash(pk),
        valid_after_ledger,
        merchant_out: m_note.commitment(),
        subscriber_out: s_note.commitment(),
        merchant_bind: bind(DOMAIN_CHANNEL_MERCHANT, merchant_pk, m_salt),
        subscriber_bind: bind(DOMAIN_ESCROW_REFUND, subscriber_pk, s_salt),
        cap,
        r_cap,
        drawn,
        r_k,
        channel_id,
        pk,
        sig_r,
        s_lo,
        s_hi,
        merchant_pk,
        m_salt,
        merchant_blinding,
        merchant_rho,
        subscriber_pk,
        s_salt,
        subscriber_blinding,
        subscriber_rho,
    }
}

/// Demo close public values, for the Rust witness-builder parity test (CH4). The signature publics
/// (cap_hash from r_cap, auth_key from pk) plus the message inputs are what the client reproduces.
#[test]
fn print_close_demo_publics() {
    let w = close_demo();
    let cap_hash = w.cap_hash;
    let auth_key = w.auth_key;
    let m_out = w.merchant_out;
    let s_out = w.subscriber_out;
    let m_bind = w.merchant_bind;
    let s_bind = w.subscriber_bind;
    println(f"close.cap_hash = {cap_hash}");
    println(f"close.auth_key = {auth_key}");
    println(f"close.merchant_out = {m_out}");
    println(f"close.subscriber_out = {s_out}");
    println(f"close.merchant_bind = {m_bind}");
    println(f"close.subscriber_bind = {s_bind}");
}

/// Print the message + commitment the signer must sign over, so the Rust signer (CH4) can produce a
/// matching signature: msg = Poseidon2([channel_id, valid_after_ledger, C_k.x, C_k.y]).
#[test]
fn print_close_signing_material() {
    let drawn = 600;
    let r_k = 0xd4a;
    let c_k = commit(drawn, r_k);
    let ckx = c_k.x;
    let cky = c_k.y;
    let msg = Poseidon2::hash([1, 50, c_k.x, c_k.y], 4);
    println(f"close.c_k.x = {ckx}");
    println(f"close.c_k.y = {cky}");
    println(f"close.msg = {msg}");
    // The cap commitment the client also opens at close.
    let c_cap = commit(1000, 0xca9);
    let capx = c_cap.x;
    let capy = c_cap.y;
    println(f"close.c_cap.x = {capx}");
    println(f"close.c_cap.y = {capy}");
}

/// The whole point of CH2: the circuit ACCEPTS a signature the native Rust signer produced (over the
/// same Poseidon2 + Grumpkin G0). A pass here pins client<->circuit Schnorr parity.
#[test]
fn close_end_to_end() {
    close_demo().run();
}

#[test(should_fail)]
fn close_rejects_drawn_over_cap() {
    let mut w = close_demo();
    // drawn must be <= cap; bumping drawn past cap (with the same commitments) must fail.
    w.drawn = w.cap + 1;
    w.run();
}

#[test(should_fail)]
fn close_rejects_tampered_signature() {
    let mut w = close_demo();
    w.s_lo = w.s_lo + 1; // not a valid response for (R, e, pk)
    w.run();
}

#[test(should_fail)]
fn close_rejects_wrong_auth_key() {
    let mut w = close_demo();
    w.auth_key = w.auth_key + 1; // not point_hash(pk)
    w.run();
}

#[test(should_fail)]
fn close_rejects_wrong_message() {
    let mut w = close_demo();
    // A signature for valid_after=50 must not validate for a different period (the signed message
    // binds valid_after_ledger), even though the contract would also gate this publicly.
    w.valid_after_ledger = 60;
    w.run();
}

#[test(should_fail)]
fn close_rejects_wrong_merchant_bind() {
    let mut w = close_demo();
    w.merchant_bind = w.merchant_bind + 1;
    w.run();
}

#[test(should_fail)]
fn close_rejects_subscriber_value_tamper() {
    let mut w = close_demo();
    // Re-pointing subscriber_out to a note of the wrong remainder breaks conservation (the circuit
    // mints exactly cap - drawn to the subscriber).
    let bad = Note {
        value: 999, // remainder must be cap - drawn = 400
        asset_tag: w.asset_tag,
        owner_pk: w.subscriber_pk,
        blinding: w.subscriber_blinding,
        epoch: w.epoch,
        rho: w.subscriber_rho,
    };
    w.subscriber_out = bad.commitment();
    w.run();
}

54.source:
//! Escrow circuits (building block B): hidden-sum invoice / multi-payer escrow.
//!
//! `verify_escrow_contribute` is withdraw-shaped (spend one owned note, shielded change) but
//! instead of releasing a public amount it folds the HIDDEN amount into a running Pedersen
//! commitment via the embedded (Grumpkin) curve: P_new = P_old + Commit(amount, r). The
//! contract only ever sees Poseidon(x, y) handles of these points, so it does no curve math.
//!
//! `verify_escrow_payout` opens a Pedersen commitment to a hidden value V, asserts V >= floor,
//! and mints a note of V to a recipient bound by `recipient_bind`. Release and refund share it
//! (release opens the running commitment with floor=target; refund opens a contribution with
//! floor=0). See claude-docs/escrow_interface.md.
use crate::transfer::{
    build_two_insertions, InputWitness, make_input, N_INPUTS, OutputWitness, single_leaf_tree,
    spend_inputs, zero_ladder,
};
use crate::{derive_owner_pk, nullifier, Note};
use poseidon::poseidon2::Poseidon2;
use std::embedded_curve_ops::EmbeddedCurvePoint;
use std::hash::pedersen_commitment;

// Domain tags for the payout bindings (ASCII; distinct so a refund proof can't pass as a
// release). Placeholders finalized before VK generation, like the other DOMAIN_* tags.
pub global DOMAIN_ESCROW_PAYEE: Field = 0x6f7a6b795f706179; // "ozky_pay"
pub global DOMAIN_ESCROW_REFUND: Field = 0x6f7a6b795f726566; // "ozky_ref"

/// Pedersen commitment Commit(v, r) = v*G0 + r*G1 over the embedded curve. Homomorphic across
/// the 2-slot layout: Commit(v0,r0) + Commit(v1,r1) == Commit(v0+v1, r0+r1).
pub fn commit(value: Field, blinding: Field) -> EmbeddedCurvePoint {
    pedersen_commitment([value, blinding])
}

/// On-chain handle for a commitment point: Poseidon2(x, y). Opaque to the contract.
pub fn point_hash(p: EmbeddedCurvePoint) -> Field {
    Poseidon2::hash([p.x, p.y], 2)
}

/// recipient_bind = Poseidon(domain, recipient_pk, salt). Only the holder of the bound key
/// (knowing salt) can mint a payout to it.
pub fn bind(domain: Field, recipient_pk: Field, salt: Field) -> Field {
    Poseidon2::hash([domain, recipient_pk, salt], 3)
}

/// The seed every escrow's running commitment starts from: the hash of the identity point
/// (an empty sum). The contract's `init_c_raised` must equal this.
pub fn empty_raised_hash() -> Field {
    point_hash(EmbeddedCurvePoint::point_at_infinity())
}

// ----------------------------- contribute -----------------------------

pub struct ContributeWitness {
    // public
    pub domain_sep: Field,
    pub asset_tag: Field,
    pub epoch: Field,
    pub commitment_root: Field,
    pub nullifier_old_root: Field,
    pub nullifier_new_root: Field,
    pub nullifiers: [Field; N_INPUTS],
    pub change_commitment: Field,
    pub asp_root: Field,
    pub c_raised_old: Field,
    pub c_raised_new: Field,
    pub c_contrib: Field,
    pub refund_bind: Field,
    // private
    pub owner_sk: Field,
    pub inputs: [InputWitness; N_INPUTS],
    pub change: OutputWitness,
    pub amount: Field,
    pub blinding_r: Field,
    pub contrib_salt: Field,
    pub p_old: EmbeddedCurvePoint,
}

#[allow(clippy::too_many_arguments)]
pub fn verify_escrow_contribute(
    domain_sep: Field,
    asset_tag: Field,
    epoch: Field,
    commitment_root: Field,
    nullifier_old_root: Field,
    nullifier_new_root: Field,
    nullifiers: [Field; N_INPUTS],
    change_commitment: Field,
    asp_root: Field,
    c_raised_old: Field,
    c_raised_new: Field,
    c_contrib: Field,
    refund_bind: Field,
    owner_sk: Field,
    inputs: [InputWitness; N_INPUTS],
    change: OutputWitness,
    amount: Field,
    blinding_r: Field,
    contrib_salt: Field,
    p_old: EmbeddedCurvePoint,
) {
    assert(domain_sep != 0);
    epoch.assert_max_bit_size::<32>();
    amount.assert_max_bit_size::<64>();
    let owner_pk = derive_owner_pk(owner_sk);

    let in_sum = spend_inputs(
        asset_tag,
        commitment_root,
        asp_root,
        owner_pk,
        owner_sk,
        nullifiers,
        nullifier_old_root,
        nullifier_new_root,
        inputs,
    );

    assert(change.commitment(asset_tag, epoch) == change_commitment);
    change.value.assert_max_bit_size::<64>();
    // conservation: spent inputs == hidden contribution + shielded change.
    assert(in_sum == amount + change.value);

    // Homomorphic fold of the hidden amount into the running commitment.
    let c = commit(amount, blinding_r);
    let p_new = p_old + c;
    assert(point_hash(p_old) == c_raised_old);
    assert(point_hash(p_new) == c_raised_new);
    assert(point_hash(c) == c_contrib);

    // Only the contributor (knowing contrib_salt + owner_sk) can later refund.
    assert(bind(DOMAIN_ESCROW_REFUND, owner_pk, contrib_salt) == refund_bind);
}

impl ContributeWitness {
    pub fn run(self) {
        verify_escrow_contribute(
            self.domain_sep,
            self.asset_tag,
            self.epoch,
            self.commitment_root,
            self.nullifier_old_root,
            self.nullifier_new_root,
            self.nullifiers,
            self.change_commitment,
            self.asp_root,
            self.c_raised_old,
            self.c_raised_new,
            self.c_contrib,
            self.refund_bind,
            self.owner_sk,
            self.inputs,
            self.change,
            self.amount,
            self.blinding_r,
            self.contrib_salt,
            self.p_old,
        );
    }
}

// ----------------------------- payout (release & refund) -----------------------------

pub struct PayoutWitness {
    // public
    pub domain_sep: Field,
    pub asset_tag: Field,
    pub epoch: Field,
    pub commitment_hash: Field,
    pub floor: Field,
    pub out_commitment: Field,
    pub recipient_bind: Field,
    // private
    pub domain_bind: Field,
    pub recipient_sk: Field,
    pub value: Field,
    pub blinding_r: Field,
    pub out_blinding: Field,
    pub out_rho: Field,
    pub salt: Field,
}

#[allow(clippy::too_many_arguments)]
pub fn verify_escrow_payout(
    domain_sep: Field,
    asset_tag: Field,
    epoch: Field,
    commitment_hash: Field,
    floor: Field,
    out_commitment: Field,
    recipient_bind: Field,
    domain_bind: Field,
    recipient_sk: Field,
    value: Field,
    blinding_r: Field,
    out_blinding: Field,
    out_rho: Field,
    salt: Field,
) {
    assert(domain_sep != 0);
    epoch.assert_max_bit_size::<32>();
    value.assert_max_bit_size::<64>();
    floor.assert_max_bit_size::<64>();

    // Open the committed value: commitment_hash pins the point, which must be Commit(value, r).
    let c = commit(value, blinding_r);
    assert(point_hash(c) == commitment_hash);
    // Threshold: value >= floor (both range-bound, so this is integer order).
    assert(!value.lt(floor));

    // Mint the payout note of `value` to the recipient.
    let recipient_pk = derive_owner_pk(recipient_sk);
    let note = Note { value, asset_tag, owner_pk: recipient_pk, blinding: out_blinding, epoch, rho: out_rho };
    assert(note.commitment() == out_commitment);

    // Recipient binding: payee_bind (release) or refund_bind (refund); the matching domain is
    // forced by the original binding the contract supplies as `recipient_bind`.
    assert(bind(domain_bind, recipient_pk, salt) == recipient_bind);
}

impl PayoutWitness {
    pub fn run(self) {
        verify_escrow_payout(
            self.domain_sep,
            self.asset_tag,
            self.epoch,
            self.commitment_hash,
            self.floor,
            self.out_commitment,
            self.recipient_bind,
            self.domain_bind,
            self.recipient_sk,
            self.value,
            self.blinding_r,
            self.out_blinding,
            self.out_rho,
            self.salt,
        );
    }
}

// ----------------------------- demo witnesses + tests -----------------------------

/// A deterministic first contribution: spend 1000, contribute 700 (hidden), 300 change. The
/// running commitment starts at the identity, so p_new = Commit(700, r). Parameterized by
/// `epoch`/`domain_sep` to bind a live pool; spends the note `deposit::demo_witness_at` mints.
pub fn contribute_demo_at(epoch: Field, domain_sep: Field) -> ContributeWitness {
    let z = zero_ladder();
    let asset_tag = 1;
    let owner_sk = 12345;
    let owner_pk = derive_owner_pk(owner_sk);

    let in_note = Note { value: 1000, asset_tag, owner_pk, blinding: 777, epoch, rho: 111 };
    let (commitment_root, cm_ir, cm_sib) = single_leaf_tree(in_note.commitment(), z);
    let (asp_root, asp_ir, asp_sib) = single_leaf_tree(owner_pk, z);

    let change = OutputWitness { value: 300, owner_pk, blinding: 444, rho: 555 };

    let dummy_rho = 0xdead;
    let nf0 = nullifier(111, owner_sk);
    let nf1 = nullifier(dummy_rho, owner_sk);
    let (nf_old, nf_new, w0, w1) = build_two_insertions(nf0, nf1);

    let real_in = make_input(1000, 777, epoch, 111, false, cm_ir, cm_sib, asp_ir, asp_sib, w0);
    let dummy_in = make_input(
        0,
        0,
        epoch,
        dummy_rho,
        true,
        [false; crate::merkle::TREE_DEPTH],
        [0; crate::merkle::TREE_DEPTH],
        [false; crate::merkle::TREE_DEPTH],
        [0; crate::merkle::TREE_DEPTH],
        w1,
    );

    let amount = 700;
    let blinding_r = 0xb11d;
    let contrib_salt = 0x5a17;
    let p_old = EmbeddedCurvePoint::point_at_infinity();
    let c = commit(amount, blinding_r);
    let p_new = p_old + c;

    ContributeWitness {
        domain_sep,
        asset_tag,
        epoch,
        commitment_root,
        nullifier_old_root: nf_old,
        nullifier_new_root: nf_new,
        nullifiers: [nf0, nf1],
        change_commitment: change.commitment(asset_tag, epoch),
        asp_root,
        c_raised_old: point_hash(p_old),
        c_raised_new: point_hash(p_new),
        c_contrib: point_hash(c),
        refund_bind: bind(DOMAIN_ESCROW_REFUND, owner_pk, contrib_salt),
        owner_sk,
        inputs: [real_in, dummy_in],
        change,
        amount,
        blinding_r,
        contrib_salt,
        p_old,
    }
}

pub fn contribute_demo() -> ContributeWitness {
    contribute_demo_at(5, 0xabc)
}

/// A deterministic release: open Commit(700, r) to value 700, floor=target=500 (met), mint a
/// 700 note to the payee. Parameterized by `epoch`/`domain_sep`.
pub fn payout_demo_at(epoch: Field, domain_sep: Field) -> PayoutWitness {
    let asset_tag = 1;
    let value = 700;
    let blinding_r = 0xb11d;
    let recipient_sk = 99;
    let recipient_pk = derive_owner_pk(recipient_sk);
    let salt = 0x9a17;
    let out_blinding = 222;
    let out_rho = 333;

    let c = commit(value, blinding_r);
    let note = Note { value, asset_tag, owner_pk: recipient_pk, blinding: out_blinding, epoch, rho: out_rho };

    PayoutWitness {
        domain_sep,
        asset_tag,
        epoch,
        commitment_hash: point_hash(c),
        floor: 500,
        out_commitment: note.commitment(),
        recipient_bind: bind(DOMAIN_ESCROW_PAYEE, recipient_pk, salt),
        domain_bind: DOMAIN_ESCROW_PAYEE,
        recipient_sk,
        value,
        blinding_r,
        out_blinding,
        out_rho,
        salt,
    }
}

pub fn payout_demo() -> PayoutWitness {
    payout_demo_at(5, 0xabc)
}

#[test]
fn contribute_end_to_end() {
    contribute_demo().run();
}

#[test(should_fail)]
fn contribute_rejects_value_mismatch() {
    let mut w = contribute_demo();
    w.amount = 701; // 1000 != 701 + 300
    w.run();
}

#[test(should_fail)]
fn contribute_rejects_tampered_running_hash() {
    let mut w = contribute_demo();
    w.c_raised_new = w.c_raised_new + 1; // not the hash of the actual folded point
    w.run();
}

#[test]
fn payout_end_to_end() {
    payout_demo().run();
}

#[test(should_fail)]
fn payout_rejects_value_below_floor() {
    let mut w = payout_demo();
    // Re-open a commitment to 400 with floor still 500: 400 < 500 must fail.
    let value = 400;
    let c = commit(value, w.blinding_r);
    let note = Note {
        value,
        asset_tag: w.asset_tag,
        owner_pk: derive_owner_pk(w.recipient_sk),
        blinding: w.out_blinding,
        epoch: w.epoch,
        rho: w.out_rho,
    };
    w.value = value;
    w.commitment_hash = point_hash(c);
    w.out_commitment = note.commitment();
    w.run();
}

#[test(should_fail)]
fn payout_rejects_wrong_recipient_bind() {
    let mut w = payout_demo();
    w.recipient_bind = w.recipient_bind + 1; // not bind(domain, recipient_pk, salt)
    w.run();
}

/// Pedersen parity reference vectors for the Rust client (E4). Grumpkin's base field IS the
/// BN254 scalar field the core already uses, so the client reproduces `commit(v,r) = v*G0 + r*G1`
/// with these exact generators. Printed via `nargo test --show-output`; the client's
/// `pedersen` module is pinned against them.
#[test]
fn print_pedersen_parity_vectors() {
    // Generators: G0 = commit(1, 0), G1 = commit(0, 1). (Noir format strings take only bare
    // identifiers, so each field is bound to a local first.)
    let g0 = commit(1, 0);
    let g1 = commit(0, 1);
    let g0x = g0.x;
    let g0y = g0.y;
    let g1x = g1.x;
    let g1y = g1.y;
    println(f"G0.x = {g0x}");
    println(f"G0.y = {g0y}");
    println(f"G1.x = {g1x}");
    println(f"G1.y = {g1y}");
    // Seed for an empty escrow (identity point hash) -> contract init_c_raised.
    let empty = empty_raised_hash();
    println(f"empty_raised_hash = {empty}");
    // A sample commitment + its on-chain handle (the client must reproduce exactly).
    let c = commit(700, 0xb11d);
    let cx = c.x;
    let cy = c.y;
    let ch = point_hash(c);
    println(f"commit_700_b11d.x = {cx}");
    println(f"commit_700_b11d.y = {cy}");
    println(f"point_hash_700_b11d = {ch}");
    // A bind sample: bind(DOMAIN_ESCROW_REFUND, derive_owner_pk(12345), 0x5a17).
    let rb = bind(DOMAIN_ESCROW_REFUND, derive_owner_pk(12345), 0x5a17);
    println(f"refund_bind_sample = {rb}");
}

/// Escrow-specific public values of the contribute/payout demos (epoch 5, domain_sep 0xabc),
/// for the Rust witness-builder parity test (E4). The spend-side publics (roots, nullifiers) are
/// already covered by the withdraw parity; these are the NEW escrow fields.
#[test]
fn print_escrow_demo_publics() {
    let c = contribute_demo();
    let c_old = c.c_raised_old;
    let c_new = c.c_raised_new;
    let c_con = c.c_contrib;
    let c_rb = c.refund_bind;
    let c_chg = c.change_commitment;
    println(f"contribute.c_raised_old = {c_old}");
    println(f"contribute.c_raised_new = {c_new}");
    println(f"contribute.c_contrib = {c_con}");
    println(f"contribute.refund_bind = {c_rb}");
    println(f"contribute.change_commitment = {c_chg}");

    let p = payout_demo();
    let p_ch = p.commitment_hash;
    let p_oc = p.out_commitment;
    let p_rb = p.recipient_bind;
    println(f"payout.commitment_hash = {p_ch}");
    println(f"payout.out_commitment = {p_oc}");
    println(f"payout.recipient_bind = {p_rb}");
}

/// The two homomorphic folds compose: contributing v0 then v1 yields a running commitment whose
/// hash equals Commit(v0+v1, r0+r1)'s hash (the payee can open the total).
#[test]
fn running_commitment_is_homomorphic() {
    let p0 = EmbeddedCurvePoint::point_at_infinity();
    let c0 = commit(700, 0xb11d);
    let p1 = p0 + c0;
    let c1 = commit(250, 0x1234);
    let p2 = p1 + c1;
    // Opening with the summed value + summed blinding reproduces the same point.
    let opened = commit(700 + 250, 0xb11d + 0x1234);
    assert(point_hash(p2) == point_hash(opened));
}

